const now = new Date();

const temp = $json.main?.temp;
const humidity = $json.main?.humidity;
const weatherMain = $json.weather?.[0]?.main || 'Unknown';
const weatherDesc = $json.weather?.[0]?.description || '';
const wind = $json.wind?.speed || 0;

// date key for dedupe (YYYY-MM-DD in local TZ approx)
const dateKey = now.toISOString().slice(0,10);

return [{
  city: $json.name || $node["Set City"].json.city,
  temp,
  humidity,
  weatherMain,
  weatherDesc,
  wind,
  dateKey
}];

const data = $json;
const store = this.getWorkflowStaticData('global');
const key = `${data.city}:${data.dateKey}`;

if (store[key]) {
  return [{ skip: true, reason: 'already_sent_today', ...data }];
}

store[key] = true;
return [{ skip: false, ...data }];

const { temp, humidity, weatherMain, wind } = $json;

// 🌐 language selector
const lang = $json.lang || 'th';

// helper translate
const t = (th, en) => lang === 'th' ? th : en;

// 🌍 GLOBAL SEASON CLASSIFICATION
let season = 'unknown';

if (['Rain','Drizzle','Thunderstorm'].includes(weatherMain)) {
  season = 'rainy';
} 
else if (temp >= 30) {
  season = 'summer';
} 
else if (temp >= 20) {
  season = 'spring';
} 
else if (temp >= 10) {
  season = 'autumn';
} 
else {
  season = 'winter';
}

// 🎯 RULE ENGINE
let preparation = new Set();
let warnings = new Set();
let avoid = new Set();

// 🌧️ RAINY
if (season === 'rainy') {
  preparation.add(t('ควรพกร่มหรือสวมเสื้อกันฝนเพื่อป้องกันการเปียกฝน','Carry an umbrella or wear a raincoat to stay dry'));
  preparation.add(t('ควรสวมรองเท้าที่กันลื่นเพื่อลดความเสี่ยงในการลื่นล้ม','Wear non-slip shoes to reduce slipping risk'));

  warnings.add(t('ถนนอาจลื่นและทัศนวิสัยลดลงในขณะฝนตก','Roads may be slippery and visibility may be reduced'));

  avoid.add(t('หลีกเลี่ยงการเดินหรือขับรถผ่านพื้นที่น้ำท่วมขัง','Avoid walking or driving through flooded areas'));
}

// ☀️ SUMMER
if (season === 'summer') {
  preparation.add(t('ควรดื่มน้ำให้เพียงพอตลอดวันเพื่อป้องกันภาวะขาดน้ำ','Drink plenty of water to stay hydrated'));

  warnings.add(t('อุณหภูมิสูงอาจทำให้เกิดอาการอ่อนเพลียหรือขาดน้ำ','High temperature may cause fatigue or dehydration'));

  if (temp >= 35) {
    warnings.add(t('มีความเสี่ยงเกิดโรคลมแดด','Risk of heatstroke'));
    avoid.add(t('หลีกเลี่ยงกิจกรรมกลางแจ้งช่วงแดดจัด','Avoid outdoor activities during peak sunlight hours'));
  }
}

// 🌱 SPRING
if (season === 'spring') {
  preparation.add(t('ควรสวมเสื้อผ้าที่ใส่สบายเหมาะกับอากาศ','Wear comfortable clothing for mild weather'));
  warnings.add(t('สภาพอากาศอาจเปลี่ยนแปลงบ่อย','Weather may change frequently'));
}

// 🍂 AUTUMN
if (season === 'autumn') {
  preparation.add(t('ควรพกเสื้อคลุมหรือเสื้อแขนยาว','Bring a light jacket or long sleeves'));
  warnings.add(t('อากาศเย็นอาจทำให้เป็นหวัดได้','Cool weather may increase risk of catching a cold'));
}

// ❄️ WINTER
if (season === 'winter') {
  preparation.add(t('ควรสวมเสื้อผ้าหนาเพื่อให้ร่างกายอบอุ่น','Wear warm clothing to stay warm'));
  warnings.add(t('อากาศหนาวอาจส่งผลต่อสุขภาพ','Cold weather may affect health'));

  if (temp <= 0) {
    warnings.add(t('อุณหภูมิต่ำมาก อาจเกิดน้ำแข็ง','Freezing conditions may occur'));
    avoid.add(t('หลีกเลี่ยงการอยู่กลางแจ้งนานเกินไป','Avoid prolonged outdoor exposure'));
  }
}

// 💧 HUMIDITY
if (humidity >= 90) {
  warnings.add(t('ความชื้นสูงมาก อาจทำให้หายใจลำบาก','Very high humidity may cause discomfort'));
}
else if (humidity <= 30) {
  warnings.add(t('ความชื้นต่ำ อาจทำให้ผิวแห้ง','Low humidity may cause dry skin'));
}

// 🌬 WIND
if (wind > 15) {
  warnings.add(t('ลมแรงมาก อาจเกิดอันตราย','Very strong winds may be dangerous'));
  avoid.add(t('หลีกเลี่ยงกิจกรรมกลางแจ้ง','Avoid outdoor activities'));
}

// 🧠 DEFAULT FALLBACK
const defaultPrep = [
  t('ควรตรวจสอบพยากรณ์อากาศก่อนออกจากบ้าน','Check the weather forecast before going out'),
  t('ควรเตรียมอุปกรณ์ให้เหมาะกับสภาพอากาศ','Prepare appropriate gear for the weather'),
  t('ควรดูแลสุขภาพและพักผ่อนให้เพียงพอ','Take care of your health and get enough rest')
];

const defaultWarn = [
  t('สภาพอากาศอาจเปลี่ยนแปลงได้ตลอดเวลา','Weather conditions may change unexpectedly'),
  t('ควรระวังผลกระทบต่อสุขภาพ','Be aware of health impacts'),
  t('ควรติดตามข่าวสารหรือประกาศเตือนภัย','Stay updated with weather alerts')
];

const defaultAvoid = [
  t('หลีกเลี่ยงการอยู่กลางแจ้งเป็นเวลานาน','Avoid prolonged outdoor exposure'),
  t('หลีกเลี่ยงกิจกรรมที่เสี่ยง','Avoid risky activities'),
  t('หลีกเลี่ยงพื้นที่ที่อาจเกิดอันตราย','Avoid potentially dangerous areas')
];

// helper เติมให้ครบ 3
const ensureMin = (set, defaults) => {
  const arr = Array.from(set);
  for (let i = 0; arr.length < 3 && i < defaults.length; i++) {
    if (!arr.includes(defaults[i])) {
      arr.push(defaults[i]);
    }
  }
  return arr;
};

// 📦 RETURN
return [{
  ...$json,
  lang,
  season,
  preparation: ensureMin(preparation, defaultPrep),
  warnings: ensureMin(warnings, defaultWarn),
  avoid: ensureMin(avoid, defaultAvoid)
}];

const d = $json;

// helper format
const fmt = (arr) => (arr && arr.length ? arr.map(x => `- ${x}`).join('\n') : '- ไม่มี');

// 🌈 emoji ครบทุก season
const emojiMap = {
  rainy: '🌧️',
  summer: '🌞',
  spring: '🌱',
  autumn: '🍂',
  winter: '❄️'
};

const emoji = emojiMap[d.season] || '🌍';

// 🧠 Insight summary (ให้เหมือน AI)
let summary = '';

if (d.season === 'rainy') {
  summary = 'สภาพอากาศมีฝนตก ควรเตรียมอุปกรณ์กันฝนและระวังการเดินทาง';
} else if (d.season === 'summer') {
  summary = 'อากาศร้อน ควรดูแลร่างกายและหลีกเลี่ยงแดดจัด';
} else if (d.season === 'winter') {
  summary = 'อากาศเย็น ควรรักษาความอบอุ่นของร่างกาย';
} else if (d.season === 'spring') {
  summary = 'อากาศกำลังสบาย แต่มีการเปลี่ยนแปลงได้ง่าย';
} else if (d.season === 'autumn') {
  summary = 'อากาศเริ่มเย็นลง ควรเตรียมเสื้อผ้าให้เหมาะสม';
}

// 💧 humidity label
let humidityText = '';
if (d.humidity >= 90) {
  humidityText = 'สูงมาก';
} else if (d.humidity >= 80) {
  humidityText = 'สูง';
} else if (d.humidity <= 30) {
  humidityText = 'ต่ำ';
} else {
  humidityText = 'ปกติ';
}

// 🌬 wind label
let windText = '';
if (d.wind > 15) {
  windText = 'ลมแรงมาก';
} else if (d.wind > 10) {
  windText = 'ลมแรง';
} else {
  windText = 'ลมปกติ';
}

// 📦 final content
const content = `${emoji} ${d.city}

🌡 อุณหภูมิ: ${d.temp}°C
🌤 สภาพอากาศ: ${d.weatherDesc}
💧 ความชื้น: ${d.humidity}% (${humidityText})
🌬 ลม: ${d.wind} m/s (${windText})

🧠 ภาพรวม:
${summary}

🧳 การเตรียมตัว:
${fmt(d.preparation)}

⚠️ ข้อควรระวัง:
${fmt(d.warnings)}

🚫 สิ่งที่ควรหลีกเลี่ยง:
${fmt(d.avoid)}
=========================================================================================
`;


return [{ content }];
